+        switch self.currentStep {
+        case .selectType:
+            self.selectedTemplate != nil ? "Next" : "Select Provider"
+        case .configure:
+            "Next"
+        case .test:
+            self.testResult?.isSuccess == true ? "Add Provider" : "Test First"
+        }
