+    private var canNavigate: Bool {
+        switch self.currentStep {
+        case .selectType:
+            self.selectedTemplate != nil
+        case .configure:
+            self.isConfigurationValid
+        case .test:
+            self.testResult?.isSuccess == true
+        }
